          old: { type: "expression", value: "i<=3?40:80" },
          nv: { type: "expression", value: "i===0?36:i===1?32:i===2?30:i===3?20:i===4?72:i===5?64:i===6?60:40" },
          pct: { type: "expression", value: "i===0?10:i===1?20:i===2?25:i===3?50:i===4?10:i===5?20:i===6?25:50" }
